function clone(value) { return JSON.parse(JSON.stringify(value)); }
function loadState() {
  try {
    const saved = JSON.parse(localStorage.getItem(STORAGE_KEY));
    return saved ? { ...clone(DEFAULT_STATE), ...saved, project: { ...DEFAULT_STATE.project, ...(saved.project || {}) }, phaseStatus: { ...DEFAULT_STATE.phaseStatus, ...(saved.phaseStatus || {}) } } : clone(DEFAULT_STATE);
  } catch { return clone(DEFAULT_STATE); }
}
function saveState(message) { localStorage.setItem(STORAGE_KEY, JSON.stringify(state)); renderAll(); if (message) showToast(message); }
function el(id) { return document.getElementById(id); }
function escapeHtml(value = "") { return String(value).replace(/[&<>'"]/g, char => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", "'": "&#39;", '"': "&quot;" })[char]); }
function phaseById(id) { return PHASES.find(phase => phase.id === id) || PHASES[0]; }
function workById(id) { return state.workItems.find(item => item.id === id); }
function protocolById(id) { return state.protocols.find(item => item.id === id); }
function requirementById(id) { return state.requirements.find(item => item.id === id); }
function materialById(id) { return state.materials.find(item => item.id === id); }
function formatDate(value) { return value ? new Intl.DateTimeFormat("en-US", { month: "short", day: "numeric", year: "numeric" }).format(new Date(`${value}T12:00:00`)) : "Not set"; }
function shortDate(value) { return value ? new Intl.DateTimeFormat("en-US", { month: "short", day: "numeric" }).format(new Date(`${value}T12:00:00`)) : ""; }
function statusClass(value = "") { const v = value.toLowerCase(); if (["complete", "completed", "approved", "signed", "pass", "qualified", "active"].includes(v)) return "success"; if (["at-risk", "risk", "hold", "open", "in review"].includes(v)) return v === "at-risk" || v === "risk" ? "danger" : "warning"; return "neutral"; }
function nextId(prefix, collection) { const max = collection.reduce((value, item) => Math.max(value, Number(item.id.split("-").pop()) || 0), 0); return `${prefix}-${String(max + 1).padStart(3, "0")}`; }
function splitIds(value) { return String(value || "").split(",").map(item => item.trim()).filter(Boolean); }
function showToast(message) { const toast = el("toast"); toast.textContent = message; toast.classList.add("show"); clearTimeout(showToast.timer); showToast.timer = setTimeout(() => toast.classList.remove("show"), 2300); }
function modeBadge(mode) { return `<span class="badge ${escapeHtml(mode)}">${escapeHtml(mode.charAt(0).toUpperCase() + mode.slice(1))}</span>`; }
function empty(message, detail = "") { return `<div class="empty-state"><strong>${escapeHtml(message)}</strong>${escapeHtml(detail)}</div>`; }
function optionList(items, selected, label = item => item.title, blank = "None") { return `<option value="">${blank}</option>${items.map(item => `<option value="${item.id}" ${item.id === selected ? "selected" : ""}>${escapeHtml(label(item))}</option>`).join("")}`; }
function phaseOptions(selected, all = false) { return `${all ? '<option value="all">All phases</option>' : ""}${PHASES.map(phase => `<option value="${phase.id}" ${phase.id === selected ? "selected" : ""}>${String(phase.number).padStart(2, "0")} · ${escapeHtml(phase.title)}</option>`).join("")}`; }

function relatedEntries(workId) { return state.notebookEntries.filter(entry => entry.workItemId === workId); }
function relatedRuns(workId) { return state.runs.filter(run => run.workItemId === workId); }
function relatedKnowledge(workId) { return state.knowledge.filter(record => record.workItemIds.includes(workId)); }
function evidenceForPhase(phaseId, mode) {
  const entries = state.notebookEntries.filter(item => item.phaseId === phaseId && (item.mode === mode || item.mode === "combined"));
  const runs = state.runs.filter(run => workById(run.workItemId)?.phaseId === phaseId && run.mode === mode);
  const records = state.knowledge.filter(item => item.phaseId === phaseId && (item.mode === mode || item.mode === "combined"));
  return [
    ...entries.map(item => ({ id: item.id, title: item.title, meta: `Notebook · ${item.status}`, kind: "entry", state: item.status })),
    ...runs.map(item => ({ id: item.id, title: `${protocolById(item.protocolId)?.title || "Experiment"} · ${item.id}`, meta: `Run · ${item.result}`, kind: "run", state: item.status })),
    ...records.map(item => ({ id: item.id, title: item.title, meta: `${item.type} · ${item.status}`, kind: "knowledge", state: item.status }))
  ];
}
function requirementEvidence(requirementId) {
  const entries = state.notebookEntries.filter(item => item.requirementIds.includes(requirementId) && item.status === "Signed");
  const runs = state.runs.filter(run => run.status === "Complete" && (protocolById(run.protocolId)?.requirementIds || []).includes(requirementId));
  const records = state.knowledge.filter(item => item.requirementIds.includes(requirementId) && ["Approved", "Active"].includes(item.status));
  return [...entries, ...runs, ...records];
}
function phaseReadiness(phaseId) {
  const work = state.workItems.filter(item => item.phaseId === phaseId && item.type !== "milestone");
  const entries = state.notebookEntries.filter(item => item.phaseId === phaseId);
  const reqIds = [...new Set(work.flatMap(item => item.requirementIds))];
  const virtual = evidenceForPhase(phaseId, "virtual");
  const real = evidenceForPhase(phaseId, "real");
  const criteria = [
    { label: "Planned work is complete", detail: `${work.filter(item => item.status === "complete").length} of ${work.length} work items complete`, met: work.length > 0 && work.every(item => item.status === "complete") },
    { label: "Work is documented", detail: `${entries.filter(item => item.status === "Signed").length} signed notebook entries`, met: entries.some(item => item.status === "Signed") },
    { label: "Requirements have evidence", detail: `${reqIds.filter(id => requirementEvidence(id).length).length} of ${reqIds.length} linked requirements covered`, met: reqIds.length === 0 ? entries.length > 0 : reqIds.every(id => requirementEvidence(id).length > 0) },
    { label: "Virtual and real evidence agree", detail: `${virtual.length} virtual · ${real.length} real records`, met: virtual.length > 0 && real.length > 0 }
  ];
  return { criteria, score: Math.round(criteria.filter(item => item.met).length / criteria.length * 100) };
}

function setView(view) {
  activeView = view;
  document.querySelectorAll("[data-view-panel]").forEach(panel => panel.classList.toggle("active", panel.dataset.viewPanel === view));
  document.querySelectorAll(".nav-item").forEach(item => item.classList.toggle("active", item.dataset.view === view));
  el("breadcrumbView").textContent = ({ intro: "Introduction", today: "Today", plan: "Plan", notebook: "Notebook", experiments: "Experiments", phases: "Phase reviews", knowledge: "Project knowledge" })[view] || view;
  el("sidebar").classList.remove("open");
  window.scrollTo({ top: 0, behavior: "smooth" });
}

function renderAll() {
  renderChrome(); renderToday(); renderPlan(); renderNotebook(); renderExperiments(); renderPhases(); renderKnowledge();
}
function renderChrome() {
  const phase = phaseById(state.project.currentPhase);
  const readiness = phaseReadiness(phase.id);
  el("projectShortName").textContent = state.project.shortName;
  el("projectProgram").textContent = state.project.program;
  el("sidebarPhaseNumber").textContent = `${String(phase.number).padStart(2, "0")} / 12`;
  el("sidebarPhaseTitle").textContent = phase.title;
  el("sidebarPhaseProgress").style.width = `${phase.number / 12 * 100}%`;
  el("sidebarGateState").textContent = `${readiness.criteria.filter(item => item.met).length} of 4 readiness checks met`;
  el("todayNavCount").textContent = state.workItems.filter(item => item.owner === CURRENT_USER && !["complete"].includes(item.status)).length;
  el("notebookNavCount").textContent = state.notebookEntries.filter(item => item.status === "Draft").length;
}

function renderToday() {
  const phase = phaseById(state.project.currentPhase);
  const readiness = phaseReadiness(phase.id);
  const mine = state.workItems.filter(item => item.owner === CURRENT_USER && item.status !== "complete").sort((a, b) => a.due.localeCompare(b.due));
  const signed = state.notebookEntries.filter(item => item.status === "Signed").length;
  el("projectThread").innerHTML = [
    ["Project need", state.project.shortName], ["Current work", mine[0]?.title || "No assignment"], ["Evidence", `${signed} signed entries · ${state.runs.filter(r => r.status === "Complete").length} runs`], ["Next decision", phase.gate]
  ].map((item, index) => `${index ? '<div class="thread-arrow">→</div>' : ""}<div class="thread-step ${index === 1 ? "active" : ""}"><span>${item[0]}</span><strong>${escapeHtml(item[1])}</strong></div>`).join("");
  el("todayMetrics").innerHTML = [
    [mine.length, "My open work", `${mine.filter(item => item.status === "at-risk").length} at risk`],
    [state.notebookEntries.filter(item => item.owner === CURRENT_USER && item.status === "Draft").length, "Draft entries", "Complete documentation"],
    [state.runs.filter(item => item.operator === CURRENT_USER).length, "My experiment runs", `${state.runs.filter(item => item.operator === CURRENT_USER && item.status === "Complete").length} complete`],
    [`${readiness.score}%`, "Gate readiness", phase.gate]
  ].map(item => `<div class="metric-card"><span class="metric-label">${escapeHtml(item[1])}</span><strong class="metric-value">${escapeHtml(item[0])}</strong><span class="metric-detail">${escapeHtml(item[2])}</span></div>`).join("");

  if (state.activeSession) {
    const work = workById(state.activeSession.workItemId);
    const entry = state.notebookEntries.find(item => item.id === state.activeSession.entryId);
    el("activeSessionPanel").innerHTML = `<div class="session-content"><div class="session-head"><div><span class="eyebrow">Active work session · started ${escapeHtml(state.activeSession.startedAt)}</span><h2>${escapeHtml(work?.title || "Work session")}</h2><p>${escapeHtml(work?.description || "")}</p></div><span class="badge virtual">In progress</span></div><div class="session-meta"><span class="context-pill">${phaseById(work?.phaseId).id} · ${escapeHtml(phaseById(work?.phaseId).title)}</span>${entry ? `<span class="context-pill">${entry.id} · Draft notebook</span>` : ""}${(work?.requirementIds || []).map(id => `<span class="context-pill">${id}</span>`).join("")}</div><div class="session-actions"><button class="button primary small" data-edit-entry="${entry?.id || ""}">Record progress</button><button class="button secondary small" data-open-work="${work?.id || ""}">Open workspace</button><button class="text-button" data-end-session>End session</button></div></div>`;
  } else {
    el("activeSessionPanel").innerHTML = `<div class="session-empty"><div><span class="eyebrow">Work session</span><h2>Start with the project context attached.</h2><p>Starting an assignment creates a linked draft entry so observations, results, and next actions cannot become detached from the plan.</p></div><button class="button primary" data-start-work="${mine[0]?.id || ""}">Start ${escapeHtml(mine[0]?.id || "work")}</button></div>`;
  }

  el("assignmentList").innerHTML = mine.length ? mine.map(item => `<div class="assignment"><span class="task-state ${item.status === "at-risk" ? "risk" : ""}">${item.progress}%</span><div><strong>${escapeHtml(item.title)}</strong><small>${phaseById(item.phaseId).id} · due ${shortDate(item.due)} · ${relatedEntries(item.id).length} entries · ${relatedRuns(item.id).length} runs</small></div><div class="assignment-actions"><button class="button secondary small" data-open-work="${item.id}">Open</button><button class="button primary small" data-start-work="${item.id}">Start</button></div></div>`).join("") : empty("No open assignments", "Your assigned work is complete.");
  const risks = [
    ...state.workItems.filter(item => item.status === "at-risk").map(item => ({ title: item.title, detail: item.description, badge: "At risk", workId: item.id })),
    ...state.notebookEntries.filter(item => item.status === "Draft").slice(0, 2).map(item => ({ title: `${item.id} needs completion`, detail: item.nextAction, badge: "Draft", workId: item.workItemId }))
  ];
  el("attentionList").innerHTML = risks.map(item => `<div class="attention-item"><strong>${escapeHtml(item.title)}</strong><p>${escapeHtml(item.detail)}</p><div class="attention-meta"><span class="badge warning">${escapeHtml(item.badge)}</span><button class="text-button" data-open-work="${item.workId}">Resolve -></button></div></div>`).join("") || empty("Nothing needs attention");
  el("activityList").innerHTML = state.activity.slice(0, 5).map(item => `<button class="activity-item" data-open-work="${item.workItemId}"><strong>${escapeHtml(item.text)}</strong><small>${escapeHtml(item.detail)} · ${shortDate(item.date)}</small></button>`).join("");
  el("phasePath").innerHTML = PHASES.map(item => `<button class="phase-node ${state.phaseStatus[item.id]}" data-open-phase="${item.id}"><strong>${String(item.number).padStart(2, "0")}</strong><span>${escapeHtml(item.group)}</span></button>`).join("");
}

function renderPlan() {
  el("planPhaseFilter").innerHTML = phaseOptions(el("planPhaseFilter").value || "all", true);
  const phaseFilter = el("planPhaseFilter").value || "all";
  const items = state.workItems.filter(item => (phaseFilter === "all" || item.phaseId === phaseFilter) && (planFilter === "all" || (planFilter === "mine" && item.owner === CURRENT_USER) || (planFilter === "active" && item.status === "in-progress") || (planFilter === "risk" && item.status === "at-risk")));
  el("ganttSummary").innerHTML = [[items.length, "Visible work items"], [items.filter(i => i.status === "complete").length, "Complete"], [items.filter(i => i.status === "in-progress").length, "In progress"], [items.filter(i => i.status === "at-risk").length, "At risk"]].map(item => `<div class="gantt-summary-item"><strong>${item[0]}</strong><span>${item[1]}</span></div>`).join("");
  const header = `<div class="gantt-row gantt-header"><div class="gantt-cell gantt-task">Work item and connected evidence</div>${WEEKS.map(week => `<div class="gantt-cell">${week}</div>`).join("")}</div>`;
  const rows = items.map(item => `<div class="gantt-row"><button class="gantt-cell gantt-task" data-open-work="${item.id}"><span class="task-dot ${item.status}"></span><span><strong>${escapeHtml(item.title)}</strong><small>${item.id} · ${escapeHtml(item.owner)} · ${relatedEntries(item.id).length} entries / ${relatedRuns(item.id).length} runs</small></span></button>${WEEKS.map((week, index) => `<div class="gantt-cell">${index >= item.start && index < item.start + item.duration ? `<span class="gantt-bar ${item.type === "milestone" ? "milestone" : item.status}"></span>` : ""}</div>`).join("")}</div>`).join("");
  el("ganttChart").innerHTML = `<div class="gantt">${header}${rows || empty("No work matches this filter")}</div>`;
}

function filteredNotebookEntries() {
  const phase = el("notebookPhaseFilter").value || "all";
  const mode = el("notebookModeFilter").value || "all";
  return [...state.notebookEntries].filter(item => (notebookFilter === "all" || item.status === notebookFilter || (notebookFilter === "mine" && item.owner === CURRENT_USER)) && (phase === "all" || item.phaseId === phase) && (mode === "all" || item.mode === mode)).sort((a, b) => b.date.localeCompare(a.date));
}
function renderNotebook() {
  el("notebookPhaseFilter").innerHTML = phaseOptions(el("notebookPhaseFilter").value || "all", true);
  const entries = filteredNotebookEntries();
  if (!entries.some(item => item.id === selectedEntryId)) selectedEntryId = entries[0]?.id || "";
  el("notebookList").innerHTML = entries.length ? entries.map(item => `<button class="entry-card ${item.id === selectedEntryId ? "active" : ""}" data-select-entry="${item.id}"><div class="entry-card-head">${modeBadge(item.mode)}<span class="badge ${statusClass(item.status)}">${item.status}</span></div><strong>${escapeHtml(item.title)}</strong><p>${escapeHtml(item.objective)}</p><footer><span>${item.id} · ${escapeHtml(item.owner)}</span><span>${shortDate(item.date)}</span></footer></button>`).join("") : empty("No entries match these filters");
  const entry = state.notebookEntries.find(item => item.id === selectedEntryId);
  if (!entry) { el("notebookPreview").innerHTML = empty("Select or create an entry", "Notebook entries retain task, experiment, requirement, and material context."); return; }
  const work = workById(entry.workItemId); const protocol = protocolById(entry.protocolId);
  el("notebookPreview").innerHTML = `<div class="entry-paper-head"><div class="entry-card-head">${modeBadge(entry.mode)}<span class="badge ${statusClass(entry.status)}">${entry.status}</span></div><h2>${escapeHtml(entry.title)}</h2><p>${entry.id} · ${escapeHtml(entry.type)} · ${escapeHtml(entry.owner)} · ${formatDate(entry.date)}</p><div class="entry-context">${work ? `<button class="context-pill" data-open-work="${work.id}">${work.id} · ${escapeHtml(work.title)}</button>` : ""}<span class="context-pill">${entry.phaseId} · ${escapeHtml(phaseById(entry.phaseId).title)}</span>${protocol ? `<button class="context-pill" data-open-protocol="${protocol.id}">${protocol.id} v${protocol.version}</button>` : ""}${entry.requirementIds.map(id => `<span class="context-pill">${id}</span>`).join("")}${entry.materialIds.map(id => `<span class="context-pill">${id}</span>`).join("")}</div></div><div class="entry-sections">${[["Objective", entry.objective], ["Method / protocol", entry.method], ["Observations", entry.observations], ["Results", entry.results], ["Interpretation", entry.interpretation], ["Next action", entry.nextAction]].map(section => `<section class="entry-section"><h3>${section[0]}</h3><p>${escapeHtml(section[1] || "Not recorded")}</p></section>`).join("")}</div><footer class="entry-footer"><span class="signature">${entry.status === "Signed" ? `Signed by ${escapeHtml(entry.owner)} on ${formatDate(entry.date)}` : "Draft · changes remain editable"}</span><button class="button secondary small" data-edit-entry="${entry.id}">Edit entry</button></footer>`;
}

function renderExperiments() {
  const complete = state.runs.filter(run => run.status === "Complete");
  el("experimentMetrics").innerHTML = [[state.protocols.length, "Controlled protocols", `${state.protocols.filter(p => p.status === "Active").length} active`], [state.runs.length, "Runs recorded", `${complete.length} complete`], [complete.filter(r => r.mode === "virtual").length, "Virtual runs", "Models and simulations"], [complete.filter(r => r.mode === "real").length, "Real runs", "Physical observations"]].map(item => `<div class="metric-card"><span class="metric-label">${item[1]}</span><strong class="metric-value">${item[0]}</strong><span class="metric-detail">${item[2]}</span></div>`).join("");
  if (!state.protocols.some(item => item.id === selectedProtocolId)) selectedProtocolId = state.protocols[0]?.id || "";
  el("protocolList").innerHTML = state.protocols.map(item => { const runs = state.runs.filter(run => run.protocolId === item.id); return `<button class="protocol-card ${item.id === selectedProtocolId ? "active" : ""}" data-select-protocol="${item.id}"><header><span class="eyebrow">${item.id} · version ${item.version}</span><span class="badge ${statusClass(item.status)}">${item.status}</span></header><strong>${escapeHtml(item.title)}</strong><p>${escapeHtml(item.purpose)}</p><footer><span>${runs.length} runs</span><span>${item.requirementIds.join(" · ")}</span></footer></button>`; }).join("");
  const protocol = protocolById(selectedProtocolId);
  if (!protocol) { el("protocolDetail").innerHTML = empty("Create a protocol to begin"); return; }
  const protocolRuns = state.runs.filter(run => run.protocolId === protocol.id);
  el("protocolDetail").innerHTML = `<div class="protocol-hero"><span class="eyebrow">Controlled protocol · ${protocol.id} · v${escapeHtml(protocol.version)}</span><h2>${escapeHtml(protocol.title)}</h2><p>${escapeHtml(protocol.purpose)}</p><div class="context-pills">${protocol.requirementIds.map(id => `<span class="context-pill">${id}</span>`).join("")}${protocol.materialIds.map(id => `<span class="context-pill">${id}</span>`).join("")}<span class="context-pill">${protocol.phaseId}</span></div></div><div class="protocol-body"><section class="protocol-section"><h3>Procedure</h3><ol>${protocol.steps.map(step => `<li>${escapeHtml(step)}</li>`).join("")}</ol></section><section class="protocol-section"><h3>Acceptance criteria</h3><ol><li>${escapeHtml(protocol.acceptance)}</li><li>Record deviations and raw measurements.</li><li>Link the conclusion to a notebook entry.</li></ol></section></div><div class="run-launch"><div class="mode-launch virtual"><strong>Virtual experiment</strong><small>${protocolRuns.filter(run => run.mode === "virtual").length} runs · model, simulation, calculation, or digital analysis</small><button class="button secondary small" data-start-run="${protocol.id}" data-mode="virtual">Start virtual run</button></div><div class="mode-launch real"><strong>Real experiment</strong><small>${protocolRuns.filter(run => run.mode === "real").length} runs · physical build, bench test, field observation, or supplier evidence</small><button class="button secondary small" data-start-run="${protocol.id}" data-mode="real">Start real run</button></div></div>`;
  el("runsTableBody").innerHTML = [...state.runs].sort((a, b) => b.date.localeCompare(a.date)).map(run => { const pro = protocolById(run.protocolId); const work = workById(run.workItemId); return `<tr data-edit-run="${run.id}"><td><strong>${run.id}</strong><br><small>${shortDate(run.date)}</small></td><td class="table-title"><strong>${escapeHtml(pro?.title || "Unknown protocol")}</strong><small>${run.protocolId}</small></td><td>${modeBadge(run.mode)}</td><td>${work ? `${work.id}<br><small>${escapeHtml(work.title)}</small>` : "Unlinked"}</td><td>${escapeHtml(run.operator)}</td><td>${escapeHtml(run.result)}</td><td><span class="badge ${statusClass(run.status)}">${escapeHtml(run.status)}</span></td></tr>`; }).join("");
}

function renderPhases() {
  let lastGroup = "";
  el("phaseMenu").innerHTML = PHASES.map(phase => { const group = phase.group !== lastGroup ? `<div class="phase-menu-group">${phase.group}</div>` : ""; lastGroup = phase.group; const readiness = phaseReadiness(phase.id); return `${group}<button class="phase-menu-item ${phase.id === selectedPhaseId ? "active" : ""}" data-select-phase="${phase.id}"><span class="phase-number">${String(phase.number).padStart(2, "0")}</span><span><strong>${escapeHtml(phase.title)}</strong><small>${readiness.score}% ready · ${phase.gate}</small></span><i class="phase-state ${state.phaseStatus[phase.id]}"></i></button>`; }).join("");
  const phase = phaseById(selectedPhaseId); const readiness = phaseReadiness(phase.id); const work = state.workItems.filter(item => item.phaseId === phase.id);
  el("phaseHero").innerHTML = `<div class="phase-hero-content"><span class="eyebrow">Phase ${String(phase.number).padStart(2, "0")} · ${phase.group}</span><h2>${escapeHtml(phase.title)}</h2><p>${escapeHtml(phase.question)}</p><div class="phase-hero-meta"><span>${phase.lca}</span><span>${phase.gate}</span><span>${work.length} linked work items</span><span>${readiness.score}% ready</span></div></div>`;
  const evidenceColumn = (mode, title) => { const evidence = evidenceForPhase(phase.id, mode); return `<article class="evidence-column ${mode}"><div class="evidence-head"><div><span class="eyebrow">${mode} lab</span><h3>${title}</h3></div><span class="badge ${mode}">${evidence.length} records</span></div><div class="evidence-list">${evidence.length ? evidence.slice(0, 6).map(item => `<button class="evidence-row" data-open-evidence="${item.kind}:${item.id}"><span class="evidence-icon">${item.kind.slice(0,2).toUpperCase()}</span><span><strong>${escapeHtml(item.title)}</strong><small>${escapeHtml(item.meta)}</small></span><span class="badge ${statusClass(item.state)}">${escapeHtml(item.state)}</span></button>`).join("") : empty(`No ${mode} evidence yet`, "Create it from a linked work item.")}</div></article>`; };
  el("phaseEvidence").innerHTML = `${evidenceColumn("virtual", "Modeled evidence")}<div class="evidence-bridge"><span></span><strong>Gate</strong><span></span></div>${evidenceColumn("real", "Observed evidence")}`;
  el("phaseWork").innerHTML = `<div class="panel-heading"><div><span class="eyebrow">Work driving this phase</span><h2>Linked plan</h2></div><button class="text-button" data-add-task-phase="${phase.id}">+ Add work</button></div><div class="phase-work-list">${work.length ? work.map(item => `<button class="phase-work-item" data-open-work="${item.id}"><span><strong>${escapeHtml(item.title)}</strong><small>${item.id} · ${escapeHtml(item.owner)} · ${relatedEntries(item.id).length} entries / ${relatedRuns(item.id).length} runs</small></span><span class="badge ${statusClass(item.status)}">${item.progress}%</span></button>`).join("") : empty("No work planned for this phase")}</div>`;
  const latestDecision = [...state.gateDecisions].reverse().find(item => item.phaseId === phase.id);
  el("gateReadiness").innerHTML = `<div class="panel-heading"><div><span class="eyebrow">Derived gate readiness</span><h2>${escapeHtml(phase.gate)}</h2></div><div class="readiness-score"><div class="score-ring" style="--score:${readiness.score * 3.6}deg"><strong>${readiness.score}%</strong></div></div></div><div class="readiness-list">${readiness.criteria.map(item => `<div class="readiness-item"><span><strong>${escapeHtml(item.label)}</strong><small>${escapeHtml(item.detail)}</small></span><i class="readiness-mark ${item.met ? "met" : ""}">${item.met ? "✓" : "·"}</i></div>`).join("")}${latestDecision ? `<div class="readiness-item"><span><strong>Latest decision: ${escapeHtml(latestDecision.decision)}</strong><small>${escapeHtml(latestDecision.note)} · ${formatDate(latestDecision.date)}</small></span><span class="badge ${statusClass(latestDecision.decision)}">${escapeHtml(latestDecision.reviewer)}</span></div>` : ""}</div>`;
}

function renderKnowledge() {
  const types = [...new Set(state.knowledge.map(item => item.type))].sort();
  const selectedType = el("knowledgeTypeFilter").value || "all";
  el("knowledgeTypeFilter").innerHTML = `<option value="all">All types</option>${types.map(type => `<option ${type === selectedType ? "selected" : ""}>${escapeHtml(type)}</option>`).join("")}`;
  const categories = [["Reference", state.knowledge.filter(i => ["Literature review", "Project brief"].includes(i.type)).length], ["Market + user", state.knowledge.filter(i => ["Market analysis", "User research"].includes(i.type)).length], ["Requirements", state.requirements.length], ["Materials", state.materials.length], ["Decisions", state.gateDecisions.length]];
  el("knowledgeStats").innerHTML = categories.map(item => `<button class="knowledge-stat"><strong>${item[1]}</strong><span>${item[0]}</span></button>`).join("");
  const covered = state.requirements.filter(item => requirementEvidence(item.id).length).length;
  el("traceCoverageBadge").textContent = `${covered} of ${state.requirements.length} requirements have evidence`;
  const trace = [["Needs", "2 phases", "Customer and ecosystem"], ["Inputs", state.requirements.length, "Measurable requirements"], ["Work", state.workItems.length, "Tasks and decisions"], ["Protocols", state.protocols.length, "Controlled methods"], ["Evidence", state.notebookEntries.length + state.runs.length, "Entries and runs"], ["Circularity", "A1-D", "Lifecycle feedback"]];
  el("traceFlow").innerHTML = trace.map(item => `<div class="trace-node"><span class="eyebrow">${item[0]}</span><strong>${item[1]}</strong><p>${item[2]}</p></div>`).join("");
  const query = el("knowledgeSearch").value.trim().toLowerCase();
  const records = state.knowledge.filter(item => (selectedType === "all" || item.type === selectedType) && (!query || `${item.title} ${item.summary} ${item.owner}`.toLowerCase().includes(query)));
  el("knowledgeTableBody").innerHTML = records.map(item => `<tr data-edit-knowledge="${item.id}"><td class="table-title"><strong>${escapeHtml(item.title)}</strong><small>${escapeHtml(item.summary)}</small></td><td>${escapeHtml(item.type)}</td><td class="record-context"><span>${item.phaseId} · ${escapeHtml(phaseById(item.phaseId).group)}</span>${modeBadge(item.mode)}</td><td>${item.workItemIds.length ? item.workItemIds.join(", ") : "Project-wide"}</td><td>${escapeHtml(item.owner)}</td><td><span class="badge ${statusClass(item.status)}">${escapeHtml(item.status)}</span></td></tr>`).join("") || `<tr><td colspan="6">${empty("No records match this filter")}</td></tr>`;
  el("requirementPanel").innerHTML = `<div class="panel-heading"><div><span class="eyebrow">Design inputs</span><h2>Requirements</h2></div><span class="badge neutral">${covered}/${state.requirements.length} covered</span></div><div class="side-list">${state.requirements.map(item => { const count = requirementEvidence(item.id).length; return `<div class="side-item"><strong>${item.id} · ${escapeHtml(item.need)}</strong><small>${escapeHtml(item.target)}</small><footer><span class="badge ${statusClass(item.status)}">${escapeHtml(item.status)}</span><span>${count} evidence links</span></footer></div>`; }).join("")}</div>`;
  el("materialPanel").innerHTML = `<div class="panel-heading"><div><span class="eyebrow">Procurement</span><h2>Materials</h2></div><span class="badge neutral">${state.materials.length} tracked</span></div><div class="side-list">${state.materials.map(item => `<div class="side-item"><strong>${item.id} · ${escapeHtml(item.name)}</strong><small>${escapeHtml(item.supplier)} · ${escapeHtml(item.role)}<br>${escapeHtml(item.risk)}</small><footer><span class="badge ${statusClass(item.status)}">${escapeHtml(item.status)}</span><span>${item.recycled}% recycled</span></footer></div>`).join("")}</div>`;
}

function openDrawer(workId) {
  const work = workById(workId); if (!work) return;
  const entries = relatedEntries(work.id); const runs = relatedRuns(work.id); const records = relatedKnowledge(work.id);
  const reqs = work.requirementIds.map(requirementById).filter(Boolean); const materials = work.materialIds.map(materialById).filter(Boolean); const protocols = work.protocolIds.map(protocolById).filter(Boolean);
  const events = state.activity.filter(item => item.workItemId === work.id);
  el("workDrawer").innerHTML = `<header class="drawer-head"><div class="drawer-head-top"><span class="eyebrow">${work.id} · ${work.type} · ${phaseById(work.phaseId).id}</span><button class="icon-button" data-close-drawer aria-label="Close">x</button></div><h2>${escapeHtml(work.title)}</h2><p>${escapeHtml(work.description)}</p><div class="context-pills"><span class="badge ${statusClass(work.status)}">${escapeHtml(work.status)}</span><span class="context-pill">${escapeHtml(work.owner)}</span><span class="context-pill">Due ${shortDate(work.due)}</span></div><div class="drawer-actions"><button class="button primary" data-start-work="${work.id}">${state.activeSession?.workItemId === work.id ? "Continue session" : "Start work"}</button><button class="button secondary" data-new-entry-work="${work.id}">New entry</button>${protocols[0] ? `<button class="button secondary" data-open-protocol="${protocols[0].id}">Run experiment</button>` : ""}<button class="text-button" data-edit-task="${work.id}">Edit</button></div></header><div class="drawer-body"><section class="drawer-section"><h3>Progress</h3><div class="progress-track"><span style="width:${work.progress}%"></span></div><div class="context-pills"><span class="context-pill">${work.progress}% complete</span><span class="context-pill">${entries.length} notebook entries</span><span class="context-pill">${runs.length} experiment runs</span><span class="context-pill">${records.length} knowledge records</span></div></section><section class="drawer-section"><h3>Connected context</h3><div class="drawer-grid">${reqs.map(item => `<div class="drawer-link"><strong>${item.id} · ${escapeHtml(item.need)}</strong><small>${escapeHtml(item.target)} · ${requirementEvidence(item.id).length} evidence links</small></div>`).join("")}${protocols.map(item => `<button class="drawer-link" data-open-protocol="${item.id}"><strong>${item.id} v${item.version}</strong><small>${escapeHtml(item.title)}</small></button>`).join("")}${materials.map(item => `<div class="drawer-link"><strong>${item.id} · ${escapeHtml(item.name)}</strong><small>${escapeHtml(item.supplier)} · ${escapeHtml(item.status)}</small></div>`).join("") || `<div class="drawer-link"><strong>No linked materials</strong><small>Add them while editing this work item.</small></div>`}</div></section><section class="drawer-section"><h3>Documentation and evidence</h3><div class="drawer-grid">${entries.map(item => `<button class="drawer-link" data-open-entry="${item.id}"><strong>${item.id} · ${escapeHtml(item.title)}</strong><small>${escapeHtml(item.status)} · ${escapeHtml(item.mode)} · ${shortDate(item.date)}</small></button>`).join("")}${runs.map(item => `<button class="drawer-link" data-edit-run="${item.id}"><strong>${item.id} · ${escapeHtml(protocolById(item.protocolId)?.title || "Run")}</strong><small>${escapeHtml(item.mode)} · ${escapeHtml(item.result)} · ${shortDate(item.date)}</small></button>`).join("")}${records.map(item => `<button class="drawer-link" data-edit-knowledge="${item.id}"><strong>${item.id} · ${escapeHtml(item.title)}</strong><small>${escapeHtml(item.type)} · ${escapeHtml(item.status)}</small></button>`).join("") || `<div class="drawer-link"><strong>No linked evidence yet</strong><small>Start work to create the first connected notebook entry.</small></div>`}</div></section><section class="drawer-section"><h3>Activity trail</h3><div class="drawer-timeline">${events.length ? events.map(item => `<div class="drawer-event"><strong>${escapeHtml(item.text)}</strong><small>${escapeHtml(item.detail)} · ${shortDate(item.date)}</small></div>`).join("") : `<div class="drawer-event"><strong>Work item created</strong><small>Project plan</small></div>`}</div></section></div>`;
  el("drawerBackdrop").classList.add("open"); el("drawerBackdrop").setAttribute("aria-hidden", "false");
}
function closeDrawer() { el("drawerBackdrop").classList.remove("open"); el("drawerBackdrop").setAttribute("aria-hidden", "true"); }
function openModal(eyebrow, title, body) { el("modalEyebrow").textContent = eyebrow; el("modalTitle").textContent = title; el("modalBody").innerHTML = body; el("modalBackdrop").classList.add("open"); el("modalBackdrop").setAttribute("aria-hidden", "false"); }
function closeModal() { el("modalBackdrop").classList.remove("open"); el("modalBackdrop").setAttribute("aria-hidden", "true"); }

function startWork(workId) {
  const work = workById(workId); if (!work) return;
  let entry = relatedEntries(work.id).find(item => item.status === "Draft" && item.owner === CURRENT_USER);
  if (!entry) {
    entry = { id: nextId("NB", state.notebookEntries), title: `${work.title} · work session`, type: "Work session", workItemId: work.id, phaseId: work.phaseId, protocolId: work.protocolIds[0] || "", runId: "", mode: work.protocolIds.length ? "combined" : "virtual", owner: CURRENT_USER, date: TODAY, status: "Draft", objective: work.description, method: "", observations: "", results: "", interpretation: "", nextAction: "", tags: "", requirementIds: [...work.requirementIds], materialIds: [...work.materialIds] };
    state.notebookEntries.unshift(entry);
  }
  if (work.status === "planned") work.status = "in-progress";
  work.progress = Math.max(work.progress, 10);
  state.activeSession = { workItemId: work.id, entryId: entry.id, startedAt: "today" };
  state.activity.unshift({ id: nextId("ACT", state.activity), text: `Work session started for ${work.id}`, detail: `${CURRENT_USER} opened ${entry.id}`, date: TODAY, workItemId: work.id });
  closeDrawer(); saveState("Work session started with a linked notebook entry"); openEntryModal(entry);
}

function openEntryModal(entry = null, defaults = {}) {
  const item = entry || { id: "", title: "", type: defaults.type || "Work session", workItemId: defaults.workItemId || "", phaseId: defaults.phaseId || state.project.currentPhase, protocolId: defaults.protocolId || "", runId: defaults.runId || "", mode: defaults.mode || "combined", owner: CURRENT_USER, date: TODAY, status: "Draft", objective: "", method: "", observations: "", results: "", interpretation: "", nextAction: "", tags: "", requirementIds: [], materialIds: [] };
  openModal("Structured notebook", entry ? `Edit ${entry.id}` : "New notebook entry", `<form class="form-grid" id="entryForm"><div class="field full"><label for="entryTitle">Entry title</label><input id="entryTitle" value="${escapeHtml(item.title)}" required></div><div class="field"><label for="entryType">Entry type</label><select id="entryType">${["Work session","Plan","Observation","Analysis","Meeting note","Decision","Experiment result"].map(value => `<option ${value === item.type ? "selected" : ""}>${value}</option>`).join("")}</select></div><div class="field"><label for="entryStatus">State</label><select id="entryStatus"><option ${item.status === "Draft" ? "selected" : ""}>Draft</option><option ${item.status === "Signed" ? "selected" : ""}>Signed</option></select></div><div class="form-divider">Connected context</div><div class="field"><label for="entryWork">Work item</label><select id="entryWork">${optionList(state.workItems, item.workItemId, work => `${work.id} · ${work.title}`, "Project-wide entry")}</select></div><div class="field"><label for="entryPhase">Phase</label><select id="entryPhase">${phaseOptions(item.phaseId)}</select></div><div class="field"><label for="entryProtocol">Protocol</label><select id="entryProtocol">${optionList(state.protocols, item.protocolId, protocol => `${protocol.id} v${protocol.version} · ${protocol.title}`)}</select></div><div class="field"><label for="entryRun">Experiment run</label><select id="entryRun">${optionList(state.runs, item.runId, run => `${run.id} · ${run.mode} · ${run.result}`)}</select></div><div class="field"><label for="entryMode">Evidence mode</label><select id="entryMode">${["virtual","real","combined"].map(value => `<option ${value === item.mode ? "selected" : ""}>${value}</option>`).join("")}</select></div><div class="field"><label for="entryDate">Date</label><input id="entryDate" type="date" value="${item.date}" required></div><div class="field full"><label for="entryRequirements">Requirement IDs</label><input id="entryRequirements" value="${escapeHtml(item.requirementIds.join(", "))}" placeholder="REQ-001, REQ-002"><span class="field-help">Comma-separated IDs keep this entry in the engineering trace.</span></div><div class="field full"><label for="entryMaterials">Material IDs</label><input id="entryMaterials" value="${escapeHtml(item.materialIds.join(", "))}" placeholder="MAT-001, MAT-002"></div><div class="form-divider">Notebook record</div>${[["Objective","entryObjective",item.objective],["Method / protocol","entryMethod",item.method],["Observations","entryObservations",item.observations],["Results","entryResults",item.results],["Interpretation","entryInterpretation",item.interpretation],["Next action","entryNext",item.nextAction]].map(field => `<div class="field full"><label for="${field[1]}">${field[0]}</label><textarea id="${field[1]}" ${field[0] === "Objective" ? "required" : ""}>${escapeHtml(field[2])}</textarea></div>`).join("")}<div class="field full"><label for="entryTags">Tags</label><input id="entryTags" value="${escapeHtml(item.tags)}" placeholder="baseline, Gate 2, supplier"></div><div class="modal-actions"><button type="button" class="button secondary" data-cancel-modal>Cancel</button><button type="submit" class="button primary">${item.status === "Signed" ? "Save signed entry" : "Save entry"}</button></div></form>`);
  el("entryWork").onchange = event => { const work = workById(event.target.value); if (!work) return; el("entryPhase").value = work.phaseId; el("entryProtocol").value = work.protocolIds[0] || ""; el("entryRequirements").value = work.requirementIds.join(", "); el("entryMaterials").value = work.materialIds.join(", "); };
  el("entryForm").onsubmit = event => {
    event.preventDefault();
    const data = { id: item.id || nextId("NB", state.notebookEntries), title: el("entryTitle").value.trim(), type: el("entryType").value, workItemId: el("entryWork").value, phaseId: el("entryPhase").value, protocolId: el("entryProtocol").value, runId: el("entryRun").value, mode: el("entryMode").value, owner: item.owner || CURRENT_USER, date: el("entryDate").value, status: el("entryStatus").value, objective: el("entryObjective").value.trim(), method: el("entryMethod").value.trim(), observations: el("entryObservations").value.trim(), results: el("entryResults").value.trim(), interpretation: el("entryInterpretation").value.trim(), nextAction: el("entryNext").value.trim(), tags: el("entryTags").value.trim(), requirementIds: splitIds(el("entryRequirements").value), materialIds: splitIds(el("entryMaterials").value) };
    const index = state.notebookEntries.findIndex(value => value.id === data.id); if (index >= 0) state.notebookEntries[index] = data; else state.notebookEntries.unshift(data);
    const work = workById(data.workItemId);
    if (work) { work.progress = data.status === "Signed" ? Math.max(work.progress, 85) : Math.max(work.progress, 25); if (data.status === "Signed" && data.nextAction.toLowerCase().includes("complete")) { work.progress = 100; work.status = "complete"; } }
    const run = state.runs.find(value => value.id === data.runId); if (run) run.entryId = data.id;
    if (data.status === "Signed" && state.activeSession?.entryId === data.id) state.activeSession = null;
    state.activity.unshift({ id: nextId("ACT", state.activity), text: `${data.id} ${data.status === "Signed" ? "signed" : "updated"}`, detail: `${data.title}${work ? ` · linked to ${work.id}` : ""}`, date: data.date, workItemId: data.workItemId });
    selectedEntryId = data.id; closeModal(); saveState(data.status === "Signed" ? "Entry signed and evidence links updated" : "Draft entry saved with project context");
  };
}

function openRunModal(protocolId, mode, run = null) {
  const protocol = protocolById(protocolId || run?.protocolId); if (!protocol) return;
  const item = run || { id: "", protocolId: protocol.id, workItemId: state.activeSession?.workItemId || state.workItems.find(work => work.protocolIds.includes(protocol.id))?.id || "", entryId: state.activeSession?.entryId || "", mode: mode || "virtual", operator: CURRENT_USER, date: TODAY, status: "In progress", result: "", measurement: "", conclusion: "" };
  openModal(`${item.mode} experiment`, run ? `Edit ${run.id}` : `Start ${item.mode} run`, `<form class="form-grid" id="runForm"><div class="field full"><label>Controlled protocol</label><div class="field-help"><strong>${protocol.id} v${escapeHtml(protocol.version)} · ${escapeHtml(protocol.title)}</strong><br>${escapeHtml(protocol.acceptance)}</div></div><div class="field"><label for="runWork">Work item</label><select id="runWork">${optionList(state.workItems.filter(work => work.protocolIds.includes(protocol.id)), item.workItemId, work => `${work.id} · ${work.title}`, "Select work item")}</select></div><div class="field"><label for="runMode">Mode</label><select id="runMode"><option ${item.mode === "virtual" ? "selected" : ""}>virtual</option><option ${item.mode === "real" ? "selected" : ""}>real</option></select></div><div class="field"><label for="runDate">Run date</label><input id="runDate" type="date" value="${item.date}" required></div><div class="field"><label for="runStatus">Status</label><select id="runStatus">${["In progress","Complete","Superseded"].map(value => `<option ${value === item.status ? "selected" : ""}>${value}</option>`).join("")}</select></div><div class="field full"><label for="runMeasurement">Measurements / observations</label><textarea id="runMeasurement" required>${escapeHtml(item.measurement)}</textarea></div><div class="field full"><label for="runResult">Result against acceptance criteria</label><input id="runResult" value="${escapeHtml(item.result)}" placeholder="Meets target, target gap, inconclusive" required></div><div class="field full"><label for="runConclusion">Conclusion and design learning</label><textarea id="runConclusion">${escapeHtml(item.conclusion)}</textarea></div><div class="field full"><label for="runEntry">Linked notebook entry</label><select id="runEntry">${optionList(state.notebookEntries, item.entryId, entry => `${entry.id} · ${entry.title}`, "Create a result entry after save")}</select></div><div class="modal-actions"><button type="button" class="button secondary" data-cancel-modal>Cancel</button><button type="submit" class="button primary">Save run</button></div></form>`);
  el("runForm").onsubmit = event => {
    event.preventDefault(); const id = item.id || nextId("RUN", state.runs);
    const data = { id, protocolId: protocol.id, workItemId: el("runWork").value, entryId: el("runEntry").value, mode: el("runMode").value, operator: item.operator || CURRENT_USER, date: el("runDate").value, status: el("runStatus").value, result: el("runResult").value.trim(), measurement: el("runMeasurement").value.trim(), conclusion: el("runConclusion").value.trim() };
    const index = state.runs.findIndex(value => value.id === id); if (index >= 0) state.runs[index] = data; else state.runs.unshift(data);
    const work = workById(data.workItemId); if (work) { work.status = data.status === "Complete" ? "in-progress" : work.status; work.progress = Math.max(work.progress, data.status === "Complete" ? 70 : 30); }
    state.activity.unshift({ id: nextId("ACT", state.activity), text: `${data.id} ${data.status.toLowerCase()}`, detail: `${data.mode} run · ${data.result} · ${protocol.id}`, date: data.date, workItemId: data.workItemId });
    closeModal(); saveState("Experiment run saved and evidence coverage recalculated");
    if (!data.entryId && data.status === "Complete") openEntryModal(null, { type: "Experiment result", workItemId: data.workItemId, phaseId: work?.phaseId || protocol.phaseId, protocolId: protocol.id, runId: data.id, mode: data.mode });
  };
}

function openTaskModal(task = null, defaults = {}) {
  const item = task || { id: "", title: "", phaseId: defaults.phaseId || state.project.currentPhase, owner: CURRENT_USER, due: TODAY, start: 3, duration: 2, status: "planned", progress: 0, type: "task", description: "", requirementIds: [], protocolIds: [], materialIds: [] };
  openModal("Connected work item", task ? `Edit ${task.id}` : "Add work item", `<form class="form-grid" id="taskForm"><div class="field full"><label for="taskTitle">Title</label><input id="taskTitle" value="${escapeHtml(item.title)}" required></div><div class="field full"><label for="taskDescription">Outcome / definition of done</label><textarea id="taskDescription" required>${escapeHtml(item.description)}</textarea></div><div class="field"><label for="taskPhase">Phase</label><select id="taskPhase">${phaseOptions(item.phaseId)}</select></div><div class="field"><label for="taskOwner">Owner</label><input id="taskOwner" value="${escapeHtml(item.owner)}" required></div><div class="field"><label for="taskDue">Due date</label><input id="taskDue" type="date" value="${item.due}" required></div><div class="field"><label for="taskStatus">Status</label><select id="taskStatus">${["planned","in-progress","at-risk","complete"].map(value => `<option ${value === item.status ? "selected" : ""}>${value}</option>`).join("")}</select></div><div class="field"><label for="taskProgress">Progress (%)</label><input id="taskProgress" type="number" min="0" max="100" value="${item.progress}"></div><div class="field"><label for="taskType">Type</label><select id="taskType"><option ${item.type === "task" ? "selected" : ""}>task</option><option ${item.type === "milestone" ? "selected" : ""}>milestone</option></select></div><div class="field full"><label for="taskRequirements">Requirement IDs</label><input id="taskRequirements" value="${escapeHtml(item.requirementIds.join(", "))}"></div><div class="field full"><label for="taskProtocols">Protocol IDs</label><input id="taskProtocols" value="${escapeHtml(item.protocolIds.join(", "))}"></div><div class="field full"><label for="taskMaterials">Material IDs</label><input id="taskMaterials" value="${escapeHtml(item.materialIds.join(", "))}"></div><div class="modal-actions"><button type="button" class="button secondary" data-cancel-modal>Cancel</button><button type="submit" class="button primary">Save work item</button></div></form>`);
  el("taskForm").onsubmit = event => { event.preventDefault(); const data = { ...item, id: item.id || nextId("WI", state.workItems), title: el("taskTitle").value.trim(), description: el("taskDescription").value.trim(), phaseId: el("taskPhase").value, owner: el("taskOwner").value.trim(), due: el("taskDue").value, status: el("taskStatus").value, progress: Number(el("taskProgress").value), type: el("taskType").value, requirementIds: splitIds(el("taskRequirements").value), protocolIds: splitIds(el("taskProtocols").value), materialIds: splitIds(el("taskMaterials").value) }; const index = state.workItems.findIndex(value => value.id === data.id); if (index >= 0) state.workItems[index] = data; else state.workItems.push(data); closeModal(); closeDrawer(); saveState("Work item saved with connected context"); };
}

