function openGateModal() {
  const phase = phaseById(selectedPhaseId); const readiness = phaseReadiness(phase.id); const latest = [...state.gateDecisions].reverse().find(item => item.phaseId === phase.id) || {};
  openModal("Evidence-based review", phase.gate, `<form class="form-grid" id="gateForm"><div class="field full"><label>Current readiness</label><div class="field-help">${readiness.score}% · ${readiness.criteria.filter(item => item.met).length} of 4 checks met. A decision may be recorded at any score, but unresolved evidence remains visible.</div></div><div class="field"><label for="gateDecision">Decision</label><select id="gateDecision">${["Not reviewed","Pass","Hold","Rework"].map(value => `<option ${value === latest.decision ? "selected" : ""}>${value}</option>`).join("")}</select></div><div class="field"><label for="gateReviewer">Reviewer / team</label><input id="gateReviewer" value="${escapeHtml(latest.reviewer || "Gate review team")}"></div><div class="field"><label for="gateDate">Decision date</label><input id="gateDate" type="date" value="${latest.date || TODAY}"></div><div class="field full"><label for="gateNote">Rationale, unresolved evidence, and next action</label><textarea id="gateNote" required>${escapeHtml(latest.note || "")}</textarea></div><div class="modal-actions"><button type="button" class="button secondary" data-cancel-modal>Cancel</button><button type="submit" class="button primary">Record decision</button></div></form>`);
  el("gateForm").onsubmit = event => { event.preventDefault(); const decision = el("gateDecision").value; const data = { id: nextId("GATE", state.gateDecisions), phaseId: phase.id, decision, reviewer: el("gateReviewer").value.trim(), date: el("gateDate").value, note: el("gateNote").value.trim() }; state.gateDecisions.push(data); if (decision === "Pass") { state.phaseStatus[phase.id] = "complete"; const next = PHASES[phase.number]; if (next) { state.phaseStatus[next.id] = "active"; state.project.currentPhase = next.id; selectedPhaseId = next.id; } } else if (["Hold","Rework"].includes(decision)) { state.phaseStatus[phase.id] = "active"; state.project.currentPhase = phase.id; } state.activity.unshift({ id: nextId("ACT", state.activity), text: `${phase.gate}: ${decision}`, detail: data.note, date: data.date, workItemId: state.workItems.find(item => item.phaseId === phase.id && item.type === "milestone")?.id || "" }); closeModal(); saveState("Gate decision recorded in the project history"); };
}

function searchProject(query) {
  const value = query.trim().toLowerCase(); if (!value) return;
  const results = [
    ...state.workItems.filter(item => `${item.id} ${item.title} ${item.description}`.toLowerCase().includes(value)).map(item => ({ type: "Work item", id: item.id, title: item.title, action: `data-open-work="${item.id}"` })),
    ...state.notebookEntries.filter(item => `${item.id} ${item.title} ${item.objective} ${item.results}`.toLowerCase().includes(value)).map(item => ({ type: "Notebook", id: item.id, title: item.title, action: `data-open-entry="${item.id}"` })),
    ...state.protocols.filter(item => `${item.id} ${item.title} ${item.purpose}`.toLowerCase().includes(value)).map(item => ({ type: "Protocol", id: item.id, title: item.title, action: `data-open-protocol="${item.id}"` })),
    ...state.knowledge.filter(item => `${item.id} ${item.title} ${item.summary}`.toLowerCase().includes(value)).map(item => ({ type: "Knowledge", id: item.id, title: item.title, action: `data-edit-knowledge="${item.id}"` }))
  ];
  openModal("Project search", `${results.length} results for “${query.trim()}”`, `<div class="drawer-body"><div class="drawer-grid">${results.length ? results.map(item => `<button class="drawer-link" ${item.action}><strong>${item.type} · ${item.id}</strong><small>${escapeHtml(item.title)}</small></button>`).join("") : empty("No matching project records")}</div></div>`);
}
function exportProject() {
  const payload = { exportedAt: new Date().toISOString(), framework: PHASES, ...state };
  const link = document.createElement("a"); link.href = URL.createObjectURL(new Blob([JSON.stringify(payload, null, 2)], { type: "application/json" })); link.download = `${state.project.shortName.toLowerCase().replace(/[^a-z0-9]+/g, "-")}-project.json`; document.body.appendChild(link); link.click(); link.remove(); URL.revokeObjectURL(link.href); showToast("Connected project package prepared");
}

function bindEvents() {
  document.addEventListener("click", event => {
    const nav = event.target.closest("[data-view]"); if (nav) setView(nav.dataset.view);
    const jump = event.target.closest("[data-jump]"); if (jump) setView(jump.dataset.jump);
    const work = event.target.closest("[data-open-work]"); if (work?.dataset.openWork) openDrawer(work.dataset.openWork);
    const start = event.target.closest("[data-start-work]"); if (start?.dataset.startWork) startWork(start.dataset.startWork);
    const newEntry = event.target.closest("[data-new-entry-work]"); if (newEntry) openEntryModal(null, { workItemId: newEntry.dataset.newEntryWork, phaseId: workById(newEntry.dataset.newEntryWork)?.phaseId });
    const editEntry = event.target.closest("[data-edit-entry]"); if (editEntry?.dataset.editEntry) openEntryModal(state.notebookEntries.find(item => item.id === editEntry.dataset.editEntry));
    const openEntry = event.target.closest("[data-open-entry]"); if (openEntry) { selectedEntryId = openEntry.dataset.openEntry; closeModal(); closeDrawer(); setView("notebook"); renderNotebook(); }
    const selectEntry = event.target.closest("[data-select-entry]"); if (selectEntry) { selectedEntryId = selectEntry.dataset.selectEntry; renderNotebook(); }
    const selectProtocol = event.target.closest("[data-select-protocol]"); if (selectProtocol) { selectedProtocolId = selectProtocol.dataset.selectProtocol; renderExperiments(); }
    const openProtocol = event.target.closest("[data-open-protocol]"); if (openProtocol) { selectedProtocolId = openProtocol.dataset.openProtocol; closeModal(); closeDrawer(); setView("experiments"); renderExperiments(); }
    const startRun = event.target.closest("[data-start-run]"); if (startRun) openRunModal(startRun.dataset.startRun, startRun.dataset.mode);
    const editRun = event.target.closest("[data-edit-run]"); if (editRun) { const run = state.runs.find(item => item.id === editRun.dataset.editRun); openRunModal(run?.protocolId, run?.mode, run); }
    const selectPhase = event.target.closest("[data-select-phase]"); if (selectPhase) { selectedPhaseId = selectPhase.dataset.selectPhase; renderPhases(); }
    const openPhase = event.target.closest("[data-open-phase]"); if (openPhase) { selectedPhaseId = openPhase.dataset.openPhase; setView("phases"); renderPhases(); }
    const addTaskPhase = event.target.closest("[data-add-task-phase]"); if (addTaskPhase) openTaskModal(null, { phaseId: addTaskPhase.dataset.addTaskPhase });
    const editTask = event.target.closest("[data-edit-task]"); if (editTask) openTaskModal(workById(editTask.dataset.editTask));
    const editKnowledge = event.target.closest("[data-edit-knowledge]"); if (editKnowledge) openKnowledgeModal(state.knowledge.find(item => item.id === editKnowledge.dataset.editKnowledge));
    const evidence = event.target.closest("[data-open-evidence]"); if (evidence) { const [kind, id] = evidence.dataset.openEvidence.split(":"); if (kind === "entry") { selectedEntryId = id; setView("notebook"); renderNotebook(); } if (kind === "run") { const run = state.runs.find(item => item.id === id); openRunModal(run?.protocolId, run?.mode, run); } if (kind === "knowledge") openKnowledgeModal(state.knowledge.find(item => item.id === id)); }
    if (event.target.closest("[data-close-drawer]")) closeDrawer();
    if (event.target.closest("[data-cancel-modal]")) closeModal();
    if (event.target.closest("[data-end-session]")) { state.activeSession = null; saveState("Work session ended; its entry remains in Notebook"); }
  });
  el("mobileMenu").onclick = () => el("sidebar").classList.add("open"); el("sidebarClose").onclick = () => el("sidebar").classList.remove("open");
  el("modalClose").onclick = closeModal; el("modalBackdrop").onclick = event => { if (event.target.id === "modalBackdrop") closeModal(); };
  el("drawerBackdrop").onclick = event => { if (event.target.id === "drawerBackdrop") closeDrawer(); };
  document.addEventListener("keydown", event => { if (event.key === "Escape") { closeModal(); closeDrawer(); } });
  el("quickEntryAction").onclick = () => openEntryModal(); el("quickCaptureAction").onclick = () => openEntryModal(null, { type: "Observation" }); el("addNotebookEntry").onclick = () => openEntryModal();
  el("startPriorityAction").onclick = () => { const priority = state.workItems.filter(item => item.owner === CURRENT_USER && item.status !== "complete").sort((a, b) => a.due.localeCompare(b.due))[0]; if (priority) startWork(priority.id); };
  el("addTaskAction").onclick = () => openTaskModal(); el("addProtocolAction").onclick = () => openProtocolModal(); el("addKnowledgeAction").onclick = () => openKnowledgeModal(); el("recordGateDecision").onclick = openGateModal; el("projectButton").onclick = openProjectModal; el("exportProject").onclick = exportProject;
  el("planStatusFilter").onclick = event => { const button = event.target.closest("button[data-filter]"); if (!button) return; planFilter = button.dataset.filter; el("planStatusFilter").querySelectorAll("button").forEach(item => item.classList.toggle("active", item === button)); renderPlan(); };
  el("notebookStatusFilter").onclick = event => { const button = event.target.closest("button[data-filter]"); if (!button) return; notebookFilter = button.dataset.filter; el("notebookStatusFilter").querySelectorAll("button").forEach(item => item.classList.toggle("active", item === button)); renderNotebook(); };
  el("planPhaseFilter").onchange = renderPlan; el("notebookPhaseFilter").onchange = renderNotebook; el("notebookModeFilter").onchange = renderNotebook; el("knowledgeTypeFilter").onchange = renderKnowledge; el("knowledgeSearch").oninput = renderKnowledge;
  el("globalSearch").addEventListener("keydown", event => { if (event.key === "Enter") searchProject(event.target.value); });
  el("resetDemo").onclick = () => { if (!window.confirm("Reset this demonstration workspace and remove browser changes?")) return; state = clone(DEFAULT_STATE); selectedEntryId = state.notebookEntries[0].id; selectedProtocolId = state.protocols[0].id; selectedPhaseId = state.project.currentPhase; saveState("Demonstration workspace reset"); };
}

bindEvents();
renderAll();
